/* triangle-3d.js — Interactive 3D hero triangle */
(function () {
  'use strict';

  // Build a rounded-corner triangle as a THREE.Shape or THREE.Path.
  // PathClass = THREE.Shape or THREE.Path; r = corner radius.
  function roundedTriPath(PathClass, top, br, bl, r) {
    var verts = [
      new THREE.Vector2(top[0], top[1]),
      new THREE.Vector2(br[0],  br[1]),
      new THREE.Vector2(bl[0],  bl[1]),
    ];

    // At each vertex compute where the arc enters (from prev) and exits (to next)
    var corners = verts.map(function (v, i) {
      var prev   = verts[(i + 2) % 3];
      var next   = verts[(i + 1) % 3];
      var toPrev = prev.clone().sub(v).normalize().multiplyScalar(r);
      var toNext = next.clone().sub(v).normalize().multiplyScalar(r);
      return {
        entry: v.clone().add(toPrev),
        exit:  v.clone().add(toNext),
        ctrl:  v.clone(),
      };
    });

    var p = new PathClass();
    p.moveTo(corners[0].exit.x, corners[0].exit.y);
    for (var i = 0; i < 3; i++) {
      var c = corners[(i + 1) % 3];
      p.lineTo(c.entry.x, c.entry.y);
      p.quadraticCurveTo(c.ctrl.x, c.ctrl.y, c.exit.x, c.exit.y);
    }
    p.closePath();
    return p;
  }

  function init() {
    var container = document.querySelector('.hero-triangle');
    if (!container || typeof THREE === 'undefined') return;

    container.style.pointerEvents = 'auto';
    var imgFallback = container.querySelector('img');

    // ── Renderer ─────────────────────────────────────────────────
    // Container fills the full header height (top:0 bottom:0), so
    // getSize reads the actual offsetHeight — no fixed aspect ratio.
    function getSize() {
      var w = container.offsetWidth  || 620;
      var h = container.offsetHeight || 720;
      return { w: w, h: h };
    }

    var renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    var sz = getSize();
    renderer.setSize(sz.w, sz.h);
    renderer.domElement.style.display = 'block';
    renderer.domElement.style.width   = '100%';
    renderer.domElement.style.height  = '100%';

    if (imgFallback) imgFallback.style.display = 'none';
    container.appendChild(renderer.domElement);

    // ── Scene & camera ────────────────────────────────────────────
    var scene  = new THREE.Scene();
    var VFOV_RAD = 25 * Math.PI / 180;
    // Max horizontal half-extent of the geometry (border outerV ≈ ±250, group scale 1.1).
    var TRI_HALF_W = 275;
    // Move camera back so the triangle always fits horizontally at any aspect ratio.
    function fitCameraZ(w, h) {
      var aspect = w / h;
      var zH = TRI_HALF_W / (Math.tan(VFOV_RAD / 2) * aspect) * 1.1;
      camera.aspect = aspect;
      camera.position.z = Math.max(1400, zH);
      camera.updateProjectionMatrix();
    }
    var camera = new THREE.PerspectiveCamera(25, sz.w / sz.h, 1, 3000);
    fitCameraZ(sz.w, sz.h);

    // ── Lights ────────────────────────────────────────────────────
    // Ambient 0.40: combined with emissive on body, sides read as
    // full #2D2926 on unlit faces (0.40 ambient + 0.60 emissive = 1.0).
    // Key 0.50: border #E7DBD0 on directly lit face ≈ 0.81 — warm, not blown out.
    scene.add(new THREE.AmbientLight(0xffffff, 0.30));

    var keyLight = new THREE.DirectionalLight(0xffffff, 0.50);
    keyLight.position.set(2, 3, 5);
    scene.add(keyLight);

    var rimLight = new THREE.DirectionalLight(0xffffff, 0.28);
    rimLight.position.set(-3, -1, -2);
    scene.add(rimLight);

    // ── Triangle geometry ─────────────────────────────────────────
    // Vertices derived from SVG viewBox 855 × 763, scaled × 0.5, Y-flipped, centered.
    // Sharp corner intersections computed from the actual path arcs.
    var V = { top: [0, 227], br: [239, -187], bl: [-239, -187] };

    // Corner radius: arc tangent length in SVG = 136.1 px → × 0.5 scale = 68.1 ≈ 80 (enlarged per design).
    var R = 85;

    var bodyShape = roundedTriPath(THREE.Shape, V.top, V.br, V.bl, R);

    // ── Body mesh — depth 60, #2D2926 ────────────────────────────
    var bodyGeo = new THREE.ExtrudeGeometry(bodyShape, {
      depth: 60, bevelEnabled: false,
    });
    bodyGeo.translate(0, 0, -30); // centre slab around z = 0

    // emissive flooring: ambient 0.30 × color + emissive 0.30 × color = 0.60 × color on
    // unlit sides (visible dark shadow); key brings lit face to ≈ 1.0 × color = #2D2926.
    var bodyMat = new THREE.MeshStandardMaterial({
      color: 0x2d2926, roughness: 0.9, metalness: 0.0,
      emissive: 0x2d2926, emissiveIntensity: 0.30,
    });

    // ── Border ring — depth 80, #E7DBD0 ──────────────────────────
    var bw = 6;
    var s3 = Math.sqrt(3); // equilateral bisector multiplier → uniform border width
    var outerV = {
      top: [0,                           V.top[1] + bw * 2],
      br:  [V.br[0] + bw * s3,           V.br[1] - bw],
      bl:  [V.bl[0] - bw * s3,           V.bl[1] - bw],
    };
    var borderShape = roundedTriPath(THREE.Shape, outerV.top, outerV.br, outerV.bl, R + bw);
    var borderHole  = roundedTriPath(THREE.Path,  V.top, V.br, V.bl, R);
    borderShape.holes.push(borderHole);

    var borderGeo = new THREE.ExtrudeGeometry(borderShape, {
      depth: 80, bevelEnabled: false,
    });
    borderGeo.translate(0, 0, -40); // centre 80-unit slab around z = 0

    var borderMat = new THREE.MeshStandardMaterial({
      color: 0xe7dbd0, roughness: 0.60, metalness: 0.0,
      side: THREE.DoubleSide,
    });

    // ── Assemble ──────────────────────────────────────────────────
    var group = new THREE.Group();
    group.add(new THREE.Mesh(bodyGeo,   bodyMat));
    group.add(new THREE.Mesh(borderGeo, borderMat));
    group.scale.set(1.1, 1.1, 1.1); // 10% larger per design
    scene.add(group);

    // ── Face planes — SVG inlined as base64 data URL ──────────────
    // Data URLs are always same-origin, so drawImage() never taints
    // the canvas regardless of protocol (file://, localhost, Vercel).
    //
    // SVG canvas 563 × 514 maps to Three.js units at scale 0.8:
    //   width  = 563 × 0.8 = 450.4   height = 514 × 0.8 = 411.2
    // A PlaneGeometry of that size fills the triangle face exactly.
    var SW = 855, SH = 763;          // SVG canvas dimensions
    var FACE_W = SW * 0.5;           // 427.5 — SVG canvas in Three.js units
    var FACE_H = SH * 0.5;           // 381.5

    var SVG_DATA_URL = 'data:image/svg+xml;base64,';

    var img = new Image();
    img.onload = function () {
      // Front canvas — normal
      var fc = document.createElement('canvas');
      fc.width = SW; fc.height = SH;
      fc.getContext('2d').drawImage(img, 0, 0, SW, SH);

      // Back canvas — horizontally flipped so it reads correctly from behind
      var bc   = document.createElement('canvas');
      bc.width = SW; bc.height = SH;
      var bctx = bc.getContext('2d');
      bctx.save();
      bctx.translate(SW, 0);
      bctx.scale(-1, 1);
      bctx.drawImage(img, 0, 0, SW, SH);
      bctx.restore();

      group.add(makeFace(new THREE.CanvasTexture(fc),  31));
      group.add(makeFace(new THREE.CanvasTexture(bc), -31));
    };
    img.src = SVG_DATA_URL;

    function makeFace(tex, zOffset) {
      var geo = new THREE.PlaneGeometry(FACE_W, FACE_H);
      var mat = new THREE.MeshBasicMaterial({
        map:         tex,
        transparent: true,
        depthWrite:  false,
        depthTest:   true,
        side:        THREE.DoubleSide,
      });
      var mesh        = new THREE.Mesh(geo, mat);
      mesh.position.z = zOffset;
      mesh.renderOrder = 1;
      return mesh;
    }

    // ── OrbitControls ─────────────────────────────────────────────
    var controls = null;
    if (typeof THREE.OrbitControls !== 'undefined') {
      controls = new THREE.OrbitControls(camera, renderer.domElement);
      controls.enableDamping = true;
      controls.dampingFactor = 0.06;
      controls.enableZoom    = false;
      controls.enablePan     = false;
    }

    // ── Auto-rotation — 1 rev / 6 s, pauses on drag ───────────────
    var ROT_SPEED    = (Math.PI * 2) / 6;
    var autoRotating = true;
    var resumeTimer  = null;

    renderer.domElement.addEventListener('pointerdown', function () {
      autoRotating = false;
      if (resumeTimer) clearTimeout(resumeTimer);
    });
    renderer.domElement.addEventListener('pointerup', function () {
      resumeTimer = setTimeout(function () { autoRotating = true; }, 1500);
    });

    // ── Responsive resize ─────────────────────────────────────────
    window.addEventListener('resize', function () {
      var s = getSize();
      renderer.setSize(s.w, s.h);
      fitCameraZ(s.w, s.h);
    });

    // ── Render loop ───────────────────────────────────────────────
    var prevT = 0;
    function animate(t) {
      requestAnimationFrame(animate);
      var dt = Math.min((t - prevT) / 1000, 0.05);
      prevT = t;
      if (autoRotating) group.rotation.y += ROT_SPEED * dt;
      if (controls) controls.update();
      renderer.render(scene, camera);
    }
    requestAnimationFrame(animate);
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }

}());
